# 🟢 FRONTEND (React Checkout Component)

This component:

- Accepts promo code
- Calls backend
- Displays:
  - Original Total
  - Discount
  - New Total

---

## 📁 `Checkout.js`

```jsx
import React, { useState } from "react";
import axios from "axios";

const Checkout = ({ cartTotal }) => {
  const [promoCode, setPromoCode] = useState("");
  const [discountAmount, setDiscountAmount] = useState(0);
  const [newTotal, setNewTotal] = useState(cartTotal);
  const [message, setMessage] = useState("");

  const applyPromo = async () => {
    try {
      const response = await axios.post(
        "http://localhost:5000/api/promotions/apply-coupon",
        {
          code: promoCode,
          cartTotal: cartTotal
        }
      );

      setDiscountAmount(response.data.discountAmount);
      setNewTotal(response.data.newTotal);
      setMessage(response.data.message);

    } catch (error) {
      setMessage(
        error.response?.data?.message || "Failed to apply promo code"
      );
      setDiscountAmount(0);
      setNewTotal(cartTotal);
    }
  };

  return (
    <div style={{ padding: "20px", maxWidth: "400px" }}>
      <h2>Checkout</h2>

      <div>
        <p><strong>Original Total:</strong> ${cartTotal.toFixed(2)}</p>
        <p><strong>Discount:</strong> -${discountAmount.toFixed(2)}</p>
        <p><strong>Final Total:</strong> ${newTotal.toFixed(2)}</p>
      </div>

      <div style={{ marginTop: "20px" }}>
        <input
          type="text"
          placeholder="Enter Promo Code"
          value={promoCode}
          onChange={(e) => setPromoCode(e.target.value)}
        />

        <button onClick={applyPromo} style={{ marginLeft: "10px" }}>
          Apply
        </button>
      </div>

      {message && (
        <p style={{ marginTop: "10px", color: "blue" }}>
          {message}
        </p>
      )}
    </div>
  );
};

export default Checkout;
```

